const PDFDocument = require('pdfkit');
const fs = require('fs');
const path = require('path');

const doc = new PDFDocument({ size: 'A4', margin: 50 });
const output = path.join('d:', 'ClaudeWorkspace', '04_报价管理', 'PI_amer_ly_2026-04-28.pdf');
const stream = fs.createWriteStream(output);
doc.pipe(stream);

const BLUE = '#003366';
const GRAY = '#666666';

// Helper
function line(y) {
  doc.moveTo(50, y).lineTo(545, y).strokeColor(BLUE).lineWidth(0.8).stroke();
}

// Title
doc.font('Helvetica-Bold').fontSize(20).fillColor(BLUE)
  .text('PROFORMA INVOICE', { align: 'center' });
doc.moveDown(0.5);

line(doc.y);
doc.moveDown(0.5);

// Seller
doc.font('Helvetica-Bold').fontSize(10).fillColor('#000')
  .text('SELLER:');
doc.font('Helvetica').fontSize(9)
  .text('Yiyang Xiaoxingxing Garments Co., Ltd.')
  .text('Yiyang City, Hunan Province, China');
doc.moveDown(0.3);

// Buyer
doc.font('Helvetica-Bold').fontSize(10)
  .text('BUYER:');
doc.font('Helvetica').fontSize(9)
  .text('amer ly')
  .text('Attn: Hussein')
  .text('Iraq, Nasiriyah, Dhi Qar, 64001')
  .text('Tel: (+964) 07867026589')
  .text('Final Destination: Iraq');
doc.moveDown(0.5);

line(doc.y);
doc.moveDown(0.5);

// Table
const tableTop = doc.y;
const colX = [50, 60, 190, 260, 330, 420];
const colW = [10, 130, 70, 70, 90, 80];
const headers = ['No.', 'Description', 'Qty (PCS)', 'Unit Price (USD)', 'Amount (USD)', ''];

// Draw table header
doc.font('Helvetica-Bold').fontSize(8).fillColor('#fff');
headers.forEach((h, i) => {
  doc.rect(colX[i], tableTop, colW[i], 16).fillColor(BLUE).fill().fillColor('#fff');
  doc.text(h, colX[i] + 3, tableTop + 4, { width: colW[i] - 6, align: 'center' });
});

let y = tableTop + 16;

// Draw table rows
const rows = [
  ['1', "Children's Shirt Set", '28', '3.80', '106.40', ''],
  ['', '', '', '', '', ''],
  ['', '', '', '', '', ''],
  ['', '', '', '', '', ''],
  ['Total:', '', '28', '', '106.40', ''],
];

rows.forEach((row, ri) => {
  doc.font(ri === 4 ? 'Helvetica-Bold' : 'Helvetica').fontSize(8).fillColor('#000');
  // Draw cell backgrounds
  if (ri % 2 === 0 && ri < 4) {
    row.forEach((_, ci) => {
      doc.rect(colX[ci], y, colW[ci], 16).fillColor('#f5f7fa').fill();
    });
  }
  row.forEach((val, ci) => {
    doc.rect(colX[ci], y, colW[ci], 16).strokeColor('#ccc').lineWidth(0.5).stroke();
    const align = ci === 1 ? 'left' : 'center';
    const xOff = ci === 1 ? 5 : 3;
    doc.fillColor('#000').text(val, colX[ci] + xOff, y + 4, { width: colW[ci] - 6, align });
  });
  y += 16;
});

doc.moveDown(0.5);

// Summary
y = doc.y + 10;
doc.font('Helvetica').fontSize(9).fillColor('#000')
  .text('Total Amount (Goods): USD 106.40', 50, y)
  .text('Freight (Express): USD 157.00', 50, y + 14);
doc.font('Helvetica-Bold').fontSize(11).fillColor(BLUE)
  .text('Total Amount (Including Freight): USD 263.40', 50, y + 30);

doc.moveDown(3);

// Amount in words
doc.font('Helvetica-Bold').fontSize(8).fillColor('#000')
  .text('Amount in Words: SAY U.S. DOLLARS TWO HUNDRED SIXTY-THREE AND CENTS FORTY ONLY');

doc.moveDown(0.5);
line(doc.y);
doc.moveDown(0.5);

// Terms
doc.font('Helvetica').fontSize(9)
  .text('Payment Terms: 100% T/T in advance')
  .text('Trade Terms: DAP')
  .text('Delivery Time: 1-7 days after payment')
  .text('Shipment: Express')
  .text('Quotation Validity: 2026-5-28 (for goods only)');

doc.moveDown(2);

// Note
doc.font('Helvetica-Oblique').fontSize(8).fillColor(GRAY)
  .text('Bank Information: (to be provided upon order confirmation)');

doc.moveDown(3);

// Signature
doc.font('Helvetica-Oblique').fontSize(8).fillColor(GRAY)
  .text('Authorized Signature: _____________________')
  .text('Yiyang Xiaoxingxing Garments Co., Ltd.');

doc.end();

stream.on('finish', () => {
  console.log('PDF saved to: ' + output);
});

