const XLSX = require('xlsx');
const wb = XLSX.readFile('C:/Users/Administrator/Desktop/形式发票模板.xlsx');
wb.SheetNames.forEach(name => {
  console.log('=== Sheet:', name, '===');
  const ws = wb.Sheets[name];
  const ref = ws['!ref'];
  console.log('Range:', ref);
  // Check merges
  if (ws['!merges']) {
    console.log('Merges:', JSON.stringify(ws['!merges']));
  }
  // Print all cells with content
  const keys = Object.keys(ws).filter(k => !k.startsWith('!')).sort();
  for (const k of keys) {
    const cell = ws[k];
    console.log(k + ':', cell.v, '(t:' + cell.t + ')');
  }
});
"

node -e "
const XLSX = require('xlsx');
const wb = XLSX.readFile('C:/Users/Administrator/Desktop/形式发票模板.xlsx', {cellStyles: true, cellFormula: false});
const ws = wb.Sheets['accessories'];

// Get cell styles for key cells
const keys = Object.keys(ws).filter(k => !k.startsWith('!'));
for (const k of keys) {
  const cell = ws[k];
  if (cell.s) {
    console.log(k, JSON.stringify(cell.s));
  }
}

// Check column widths
if (ws['!cols']) console.log('Cols:', JSON.stringify(ws['!cols']));
// Check row heights
if (ws['!rows']) console.log('Rows:', JSON.stringify(ws['!rows']));
"

