const PDFDocument = require('pdfkit');
const fs = require('fs');
const path = require('path');

const doc = new PDFDocument({
  size: 'A4',
  margin: 30,
  info: {
    Title: 'Proforma Invoice - amer ly',
    Author: 'Yiyang Xiaoxingxing Garments Co., Ltd.'
  }
});

const output = path.join('d:', 'ClaudeWorkspace', '04_报价管理', 'PI_amer_ly_2026-04-28.pdf');
const stream = fs.createWriteStream(output);
doc.pipe(stream);

const BLUE = '#003366';
const LIGHT_BLUE = '#e8edf4';
const DARK = '#222222';
const GRAY = '#666666';
const ML = 30; // left margin
const PW = 535; // page width - margins
const FONT = 'Helvetica';

function txt(text, opts = {}) {
  doc.font(opts.bold ? FONT + '-Bold' : FONT)
     .fontSize(opts.size || 9)
     .fillColor(opts.color || DARK)
     .font(opts.italic ? FONT + '-Oblique' : (opts.bold ? FONT + '-Bold' : FONT));
  if (opts.x !== undefined) {
    doc.text(text, opts.x, opts.y, { width: opts.w || 200, align: opts.align || 'left', lineBreak: opts.lb !== false });
  } else {
    doc.text(text, { width: opts.w || PW, align: opts.align || 'left', lineBreak: opts.lb !== false });
  }
  return doc.y;
}

function hr(y) {
  doc.moveTo(ML, y).lineTo(ML + PW, y).strokeColor(BLUE).lineWidth(0.8).stroke();
}

function cell(x, y, w, h, label, val, opts = {}) {
  // Background for header cells
  if (opts.headerBg) {
    doc.rect(x, y, w, h).fillColor(BLUE).fill();
  }
  // Border
  doc.rect(x, y, w, h).strokeColor('#bbb').lineWidth(0.4).stroke();
  // Text
  if (label) {
    doc.font(FONT + (opts.bold ? '-Bold' : '')).fontSize(8).fillColor(opts.headerBg ? '#fff' : '#888')
      .text(label, x + 2, y + 1, { width: w - 4, align: opts.align || 'left' });
  }
  if (val !== undefined && val !== null) {
    doc.font(FONT + '-Bold').fontSize(9).fillColor(DARK)
      .text(String(val), x + 2, y + (opts.labelOnly ? 0 : 12), { width: w - 4, align: opts.valAlign || opts.align || 'left' });
  }
}

let y = ML;

// === HEADER ===
txt('PROFORMA INVOICE', { size: 20, bold: true, color: BLUE, align: 'center' });
y = doc.y + 4;
txt('ORIGINAL', { size: 10, bold: true, color: BLUE, align: 'center' });
y = doc.y + 6;
hr(doc.y + 2);
y = doc.y + 8;

// === LEFT: CONSIGNEE ===
const leftX = ML;
const rightX = ML + 280;

txt('CONSIGNEE/BUYER :', { bold: true, size: 10, x: leftX, y: y });
doc.y = y;

let lines = [
  'Company: amer ly',
  'Address: Iraq, Nasiriyah, Dhi Qar, 64001',
  'Attn: Hussein',
  'Tel: (+964) 07867026589'
];
lines.forEach(l => { txt(l, { size: 9, x: leftX + 5 }); doc.y -= 2; });
y = doc.y + 4;

// === RIGHT: Invoice Info ===
txt('Invoice No. :', { size: 8, x: rightX, y: ML + 42 });
txt('LT20260428001', { bold: true, size: 9, x: rightX + 5, y: ML + 54 });

txt('Date:', { size: 8, x: rightX + 60, y: ML + 42 });
txt('2026-04-28', { bold: true, size: 9, x: rightX + 65, y: ML + 54 });

txt('Port of Loading :', { size: 8, x: rightX, y: ML + 70 });
txt('Yiyang, China  zip code: 413000', { bold: true, size: 8, x: rightX + 5, y: ML + 82 });

txt('Final Destination:', { size: 8, x: rightX, y: ML + 96 });
txt('Iraq', { bold: true, size: 9, x: rightX + 5, y: ML + 108 });

txt('Terms of Payment:', { size: 8, x: rightX, y: ML + 122 });
txt('100% T/T in advance', { bold: true, size: 9, x: rightX + 5, y: ML + 134 });

txt('Shipment :', { size: 8, x: rightX, y: ML + 148 });
txt('Express', { bold: true, size: 9, x: rightX + 5, y: ML + 160 });

txt('Trade Terms:', { size: 8, x: rightX, y: ML + 174 });
txt('DAP', { bold: true, size: 9, x: rightX + 5, y: ML + 186 });

txt('DELIVERY TIME:', { size: 8, x: rightX, y: ML + 200 });
txt('1-7 days after payment', { bold: true, size: 9, x: rightX + 5, y: ML + 212 });

// === CONFIRMATION TEXT ===
y = Math.max(y, ML + 235);
hr(y + 2);
y += 8;

doc.font(FONT + '-Oblique').fontSize(8).fillColor(GRAY)
  .text('Both sides above mutually confirm to buy and sell goods on the terms and conditions as set forth hereunder:', ML, y, { width: PW });
y = doc.y + 6;

// === TABLE ===
const colDefs = [
  { x: ML, w: 20, label: 'No.', align: 'center' },
  { x: ML + 20, w: 210, label: 'ITEM', align: 'left' },
  { x: ML + 230, w: 55, label: 'QTY', align: 'center' },
  { x: ML + 285, w: 60, label: 'Price $', align: 'center' },
  { x: ML + 345, w: 60, label: 'Total', align: 'center' },
];
const tableW = colDefs[colDefs.length-1].x + 60 - ML;

// Header row
const rowH = 18;
let x = ML;
colDefs.forEach(c => {
  doc.rect(c.x, y, c.w, rowH).fillColor(BLUE).fill();
  doc.font(FONT + '-Bold').fontSize(9).fillColor('#fff')
    .text(c.label, c.x + 2, y + 4, { width: c.w - 4, align: c.align });
});
y += rowH;

// Data rows
const dataRows = [
  ['1', "Children's Shirt Set", '28', '3.80', '106.40'],
  ['', '', '', '', ''],
  ['', '', '', '', ''],
  ['', '', '', '', ''],
];

dataRows.forEach((row, ri) => {
  // Alternate row bg
  if (ri < row.length && ri % 2 === 0) {
    doc.rect(ML, y, tableW, rowH - 1).fillColor('#f7f8fa').fill();
  }
  x = ML;
  row.forEach((val, ci) => {
    const c = colDefs[ci];
    doc.rect(x, y, c.w, rowH - 1).strokeColor('#ddd').lineWidth(0.4).stroke();
    if (val) {
      doc.font(FONT + (val === 'Total:' ? '-Bold' : '')).fontSize(8).fillColor(DARK)
        .text(val, x + 3, y + 4, { width: c.w - 6, align: c.align });
    }
    x += c.w;
  });
  y += rowH - 1;
});

// Shipping fee row
doc.rect(ML, y, tableW, rowH - 1).fillColor('#f7f8fa').fill();
doc.rect(ML, y, tableW, rowH - 1).strokeColor('#ddd').lineWidth(0.4).stroke();
doc.font(FONT).fontSize(8).fillColor(DARK)
  .text('Shipping fee', ML + 23, y + 4, { width: colDefs[1].w - 6, align: 'left' });
doc.font(FONT + '-Bold').fontSize(8).fillColor(DARK)
  .text('157.00', colDefs[4].x + 3, y + 4, { width: colDefs[4].w - 6, align: colDefs[4].align });
y += rowH - 1;

// TOTAL row
doc.rect(ML, y, tableW, rowH).fillColor(BLUE).fill();
doc.font(FONT + '-Bold').fontSize(9).fillColor('#fff')
  .text('TOTAL', ML + 23, y + 4, { width: colDefs[1].w - 6, align: 'left' });
doc.font(FONT + '-Bold').fontSize(9).fillColor('#fff')
  .text('263.40', colDefs[4].x + 3, y + 4, { width: colDefs[4].w - 6, align: colDefs[4].align });
y += rowH + 8;

// === SUMMARY ===
txt('Total Amount (Goods): USD 106.40', { size: 9, x: ML });
txt('Freight (Express): USD 157.00', { size: 9, x: ML });
doc.moveDown(0.3);
txt('Total Amount (Including Freight): USD 263.40', { size: 11, bold: true, color: BLUE, x: ML });
doc.moveDown(0.5);
txt('Amount in Words: SAY U.S. DOLLARS TWO HUNDRED SIXTY-THREE AND CENTS FORTY ONLY', { size: 8, bold: true, x: ML });
doc.moveDown(0.5);
y = doc.y + 2;
hr(y);
y += 6;

// === NOTES SECTION ===
txt('1. IMPORTANT INFORMATION:', { bold: true, size: 9, x: ML, y: y });
y = doc.y + 2;
doc.font(FONT + '-Oblique').fontSize(7.5).fillColor(GRAY)
  .text('You are asked to send the copy of bank swift by mail to sales. Then, the shipment would not be unnecessarily delay due to the bank verification omitted.', ML, y, { width: PW, align: 'left' });
y = doc.y + 4;

txt('2. BANK INFORMATION:', { bold: true, size: 9, x: ML, y: y });
y = doc.y + 2;
const bankInfo = [
  'Company Name: Yiyang Little Star Garment Co., Ltd.',
  'Beneficiary Account Number: 3996001147875',
  'Swift Code: CITIHKHXXXX',
  'Country/Region: Hong Kong',
  'Beneficiary Address: 26/F., TOWER ONE, TIME SQUARE 1 MATHESON STREET CAUSEWAY BAY HK',
  'Beneficiary Bank: CITIBANK, N.A., HONG KONG BRANCH',
  'Beneficiary Bank Address: Champion Tower, Three Garden Road, Central, Hong Kong',
  'Bank Code: 006',
  'Branch Code: 391',
];
doc.font(FONT).fontSize(7.5).fillColor(GRAY);
bankInfo.forEach((l, i) => {
  doc.text(l, ML, y + i * 11, { width: PW, align: 'left' });
});
y = doc.y + 2;

doc.font(FONT + '-Oblique').fontSize(7.5).fillColor(GRAY)
  .text('Attention: All bank charges on applicant\'s account. Please quote the PI No. on the payment remark.', ML, y, { width: PW });
y = doc.y + 4;

txt('3. ORIGIN IS CHINA AND MANUFACTURED BY YIYANG LITTLE STAR GARMENT Co., Ltd.', { bold: true, size: 8, x: ML, y: y });
y = doc.y;
doc.font(FONT).fontSize(7.5).fillColor(GRAY)
  .text('ADD: 2/F, BUILDING 4, WANLI MARKET, HIGH-TECH ZONE, YIYANG CITY, HUNAN PROVINCE, P.R.CHINA', ML, y + 10, { width: PW });
doc.text('GSM: +86-18163746616  Email: leod.chen@yiyangxiaoxingxing.com', ML, y + 20, { width: PW });
y = doc.y + 6;

doc.moveDown(2);
txt('4. QUOTATION VALIDITY: ONLY 2026-5-28 (FOR GOODS ONLY)', { bold: true, size: 9, x: ML });
doc.moveDown(0.5);
txt('5. PLEASE SIGN TO CONFIRM THE ACCEPTANCE OF THIS PI', { bold: true, size: 9, x: ML });
doc.moveDown(2);

// === SIGNATURE SECTION ===
txt('Confirmed & Accepted by:', { size: 9, x: ML });
doc.moveDown(2.5);
doc.font(FONT).fontSize(9).fillColor(DARK)
  .text('Authorized Signaturer: Leo D. Chen', ML, doc.y, { width: 250, align: 'left' });
doc.moveDown(5);

// === FOOTER ===
hr(doc.y);
doc.moveDown(0.3);
doc.font(FONT + '-Oblique').fontSize(7).fillColor(GRAY)
  .text('Working Time: Monday till Friday: 8:30~12:00, 13:00~17:30', ML, doc.y, { width: 250 });
doc.font(FONT + '-Oblique').fontSize(7).fillColor(GRAY)
  .text('I DECLARE ALL THE INFORMATION CONTAINED IN THE INVOICE TO BE TRUE AND CORRECT.', ML + 200, doc.y - 10, { width: 300, align: 'right' });

doc.end();

stream.on('finish', () => {
  console.log('PDF saved: ' + output);
});

