  ws['!cols'].forEach((c, i) => console.log('Col ' + String.fromCharCode(65+i) + ':', JSON.stringify(c)));
}

// Row heights
console.log('=== ROW HEIGHTS ===');
if (ws['!rows']) {
  ws['!rows'].forEach((r, i) => console.log('Row ' + (i+1) + ':', JSON.stringify(r)));
}

// Merges
console.log('=== MERGES ===');
if (ws['!merges']) {
  ws['!merges'].forEach(m => {
    const s = m.s, e = m.e;
    const from = String.fromCharCode(65+s.c) + (s.r+1);
    const to = String.fromCharCode(65+e.c) + (e.r+1);
    console.log(from + ':' + to);
  });
}

// Full cell details with styles
console.log('=== CELL DETAILS ===');
const keys = Object.keys(ws).filter(k => !k.startsWith('!')).sort();
for (const k of keys) {
  const cell = ws[k];
  const info = {
    v: cell.v,
    t: cell.t,
    f: cell.f || null
  };
  if (cell.s) {
    info.s = cell.s;
  }
  console.log(k + ':', JSON.stringify(info));
}
"

