// Step 1: Fill template xlsx with data using xlsx library
const XLSX = require('xlsx');

const tpl = XLSX.readFile('C:/Users/Administrator/Desktop/形式发票模板.xlsx', {cellStyles: true, cellNF: true});
const ws = tpl.Sheets['accessories'];

function setCell(ws, addr, value, type) {
  const cell = ws[addr] || {};
  cell.t = type || (typeof value === 'number' ? 'n' : 's');
  cell.v = value;
  ws[addr] = cell;
}

// Buyer info
setCell(ws, 'A5', 'Company: amer ly');
setCell(ws, 'A6', 'Address: Iraq, Nasiriyah, Dhi Qar, 64001');
setCell(ws, 'A7', 'Attn: Hussein');
setCell(ws, 'A8', 'Tel: (+964) 07867026589');

// Date
const serial = (Date.UTC(2026, 3, 28) - Date.UTC(1899, 11, 30)) / 86400000;
setCell(ws, 'N4', serial, 'n');
setCell(ws, 'O4', serial, 'n');

// Invoice No
setCell(ws, 'L5', 'LT20260428001');

// Port of Loading
setCell(ws, 'L6', 'Yiyang, China  zip code: 413000');

// Final Destination
setCell(ws, 'L7', 'Iraq');

// Payment
setCell(ws, 'L8', '100% T/T in advance');

// Shipment
setCell(ws, 'L9', 'Express');

// Trade Terms - the template has J10="Trade Terms：" and L10 is the value
// But L10 doesn't appear in the original template data, so I need to check
setCell(ws, 'L10', 'DAP');

// Delivery Time
setCell(ws, 'L11', '1-7 days after payment');

// Product table
setCell(ws, 'A15', '1');
setCell(ws, 'B15', "Children's Shirt Set");
setCell(ws, 'K15', 28);
setCell(ws, 'M15', 3.80);
setCell(ws, 'O15', 106.40);

// Shipping fee
setCell(ws, 'O16', 157.00);

// Total
setCell(ws, 'O17', 263.40);

// Validity
