import ExcelJS from 'exceljs';
import fs from 'fs';

// Fresh copy of template
const src = 'C:/Users/Administrator/Desktop/形式发票模板.xlsx';
const dst = 'd:/ClaudeWorkspace/04_报价管理/PI_amer_ly_2026-04-28.xlsx';
fs.copyFileSync(src, dst);

const wb = new ExcelJS.Workbook();
await wb.xlsx.readFile(dst);
const ws = wb.getWorksheet('accessories');

// 1. BUYER INFO (merged A5:G11)
ws.getCell('A5').value =
  'Company: amer ly\nAddress: Iraq, Nasiriyah, Dhi Qar, 64001\nAttn: Hussein\nTel: (+964) 07867026589';

// 2. N4 = "Date:" label (DO NOT TOUCH - keep original)
// 3. O4 = keep =TODAY() formula (DO NOT TOUCH)

// 4. Invoice No.
ws.getCell('L5').value = 'LT20260428001';

// 5. Final Destination
ws.getCell('L7').value = 'Iraq';

// 6. Trade Terms
ws.getCell('L10').value = 'DAP';

// 7. Delivery Time - with alignment matching L8 (left, top)
ws.getCell('L11').value = '1-7 days after payment';
ws.getCell('L11').alignment = { vertical: 'top', wrapText: true };

// 8. Product - Item (center alignment)
ws.getCell('B15').value = "Children's Shirt Set";
ws.getCell('B15').alignment = { horizontal: 'center', vertical: 'middle', wrapText: true };

// 9. QTY
ws.getCell('K15').value = 28;

// 10. Price
ws.getCell('M15').value = 3.80;

// 11. Shipping fee
ws.getCell('O16').value = 157;

// 12. Validity
ws.getCell('A27').value = '4.QUOTATION VALIDITY: ONLY 2026-5-28(FOR GOODS ONLY)';

// Save
await wb.xlsx.writeFile(dst);

// Now modify XML to change view from pageBreakPreview to normal
// (exceljs doesn't support this directly)
await wb.xlsx.writeFile(dst);

// Post-process: change view mode in XML
const JSZip = (await import('jszip')).default;
const xlsxData = fs.readFileSync(dst);
const zip = await JSZip.loadAsync(xlsxData);
const sheetXml = await zip.file('xl/worksheets/sheet1.xml').async('string');
const fixed = sheetXml.replace('view="pageBreakPreview"', '');
zip.file('xl/worksheets/sheet1.xml', fixed);
const outBuf = await zip.generateAsync({ type: 'nodebuffer' });
fs.writeFileSync(dst, outBuf);

console.log('Done! All 4 issues fixed.');

