      }
    }
  }

  // Print merged cells
  console.log('\nMerged cells:');
  ws.eachRow((row, rowNum) => {
    if (rowNum <= 34) {
      row.eachCell((cell) => {
        if (cell.isMerged) {
          console.log(cell.address + ' is merged');
        }
      });
    }
  });

  // Also check merges from the merge array
  console.log('\nAll merges from worksheet:');
  if (ws.merges && ws.merges.length > 0) {
    ws.merges.forEach(m => console.log(m.shortRange));
  }

  // Check column widths
  console.log('\nColumn widths:');
  ws.columns.forEach((col, idx) => {
    if (col) console.log('Col ' + idx + ': width=' + col.width);
  });

  // Check row heights
  console.log('\nRow heights (non-default):');
  ws.eachRow((row, rowNum) => {
    if (row.height && row.height !== 15) console.log('Row ' + rowNum + ': height=' + row.height);
  });

  // Print ALL rows 20-34 to find bank info area
  console.log('\n=== Rows 20-34 (Bank Info Area) ===');
  for (let r = 20; r <= 34; r++) {
    for (let c = 1; c <= 15; c++) {
      const cell = ws.getCell(r, c);
      if (cell.value !== undefined && cell.value !== null) {
        console.log(cell.address + ' = ' + JSON.stringify(cell.value));
      }
    }
  }
}

