const ExcelJS = require('exceljs');

async function analyzeBankAndBorders(filename, label) {
  const wb = new ExcelJS.Workbook();
  await wb.xlsx.readFile(filename);
  const ws = wb.getWorksheet('accessories');

  console.log('=== ' + label + ' ===');

  // Focus on rows 12-22 (table area + bank info)
  console.log('\n--- Rows 12-22 (Table + Bank Info) ---');
  for (let r = 12; r <= 22; r++) {
