  ws.getCell('O16').value = 157;
  ws.getCell('A27').value = '4.QUOTATION VALIDITY: ONLY 2026-5-28(FOR GOODS ONLY)';

  // Outer border: careful approach, only set border on the outer side of perimeter cells
  // Use spread to preserve existing border properties
  const thick = { style: 'medium', color: { argb: 'FF2F5496' } };

  // For each cell at the perimeter, only update the outer-facing side
  // USE SPREAD to avoid wiping existing border data

  // Top: row 1, cols A-O
  for (let c = 1; c <= 15; c++) {
    const cell = ws.getCell(1, c);
    const cur = cell.border || {};
    cell.border = Object.assign({}, cur, { top: thick });
  }

  // Bottom: row 33, cols A-O  
  for (let c = 1; c <= 15; c++) {
    const cell = ws.getCell(33, c);
    const cur = cell.border || {};
    cell.border = Object.assign({}, cur, { bottom: thick });
  }

  // Left: col A, rows 1-33
  for (let r = 1; r <= 33; r++) {
    const cell = ws.getCell(r, 1);
    const cur = cell.border || {};
    cell.border = Object.assign({}, cur, { left: thick });
  }

  // Right: col O, rows 1-33
  for (let r = 1; r <= 33; r++) {
    const cell = ws.getCell(r, 15);
    const cur = cell.border || {};
    cell.border = Object.assign({}, cur, { right: thick });
  }

  await wb.xlsx.writeFile(dst);

  // Remove pageBreakPreview
  const JSZip = (await import('jszip')).default;
  const zip = await JSZip.loadAsync(fs.readFileSync(dst));
  const sheetXml = await zip.file('xl/worksheets/sheet16.xml').async('string');
  const fixed = sheetXml.replace('view=\"pageBreakPreview\"', '');
  zip.file('xl/worksheets/sheet16.xml', fixed);
  fs.writeFileSync(dst, await zip.generateAsync({ type: 'nodebuffer' }));

  console.log('Done!');

